// @ts-nocheck --

// @ts-nocheck --

import * as fs from 'fs';
import * as path from 'path';
import * as vscode from 'vscode';

type NodeKind = 'environment' | 'library' | 'category' | 'group' | 'function';
type ParamEditorType = 'text' | 'boolean' | 'enum' | 'pathFile' | 'pathFolder' | 'handle';

type ChoiceInput = string | ChoiceSpec;

interface ChoiceSpec {
  value: string;
  description?: string;
  detail?: string;
}

interface StructuredPickerItem {
  value: string;
  label?: string;
  description?: string;
  detail?: string;
  defaultValue?: string;
  sourceTypes?: string[];
  /** Contextual data type expected by a CVI Set*Attribute value argument. */
  valueKind?: string;
  /** Suggested values shown after an attribute constant has been selected. */
  valueOptions?: StructuredPickerItem[];
  /** Editable placeholder for a CVI Set*Attribute value argument. */
  valuePlaceholder?: string;
}

interface StructuredPickerGroup {
  label?: string;
  description?: string;
  items?: StructuredPickerItem[];
}

interface StructuredPickerSection {
  label?: string;
  description?: string;
  groups?: StructuredPickerGroup[];
  items?: StructuredPickerItem[];
}

interface StructuredPickerConfig {
  title?: string;
  selectionLabel?: string;
  subtitle?: string;
  sourceTypes?: string[];
  sections?: StructuredPickerSection[];
  targetIndex?: number;
  defaultTargetIndex?: number;
  applyDefaultIfEmpty?: boolean;
  /** Allow the advanced picker to combine several constants into one bitmask expression. */
  multiSelect?: boolean;
  /** Separator used when several picker constants are combined. Defaults to the C/C++ bitwise OR operator. */
  valueSeparator?: string;
  /** Value inserted when a multi-selection is empty, for example 0 or BLUETOOTH_GATT_FLAG_NONE. */
  emptyValue?: string;
}

interface CviParameter {
  name: string;
  type: string;
  description?: string;
  editorType?: ParamEditorType;
  defaultValue?: string;
  placeholder?: string;
  presets?: ChoiceInput[];
  options?: ChoiceInput[];
  presetDescriptions?: Record<string, string>;
  presetDetails?: Record<string, string>;
  optionDescriptions?: Record<string, string>;
  optionDetails?: Record<string, string>;
  pickerConfig?: StructuredPickerConfig;
}

interface CviStructField {
  name: string;
  type: string;
  description?: string;
  declaration?: string;
  access?: 'public' | 'private' | 'protected';
}

interface CviEnumValue {
  name: string;
  value?: string;
  description?: string;
}

interface CppMethod {
  name: string;
  returnType?: string;
  signature: string;
  declaration?: string;
  description?: string;
  access?: 'public' | 'private' | 'protected';
  qualifiers?: string[];
  paramsText?: string;
  methodKind?: 'method' | 'constructor' | 'destructor' | 'operator';
}

interface CviFunction {
  name: string;
  returnType: string;
  signature: string;
  insertText: string;
  header?: string;
  environment?: string;
  library: string;
  category: string;
  description?: string;
  longDescription?: string;
  returnDescription?: string;
  notes?: string[];
  warnings?: string[];
  parameters?: CviParameter[];
  fields?: CviStructField[];
  enumValues?: CviEnumValue[];
  methods?: CppMethod[];
  symbolKind?: SymbolKind;
  declaration?: string;
  isStatic?: boolean;
}

interface CviGroup {
  name: string;
  description?: string;
  functions?: CviFunction[];
  groups?: CviGroup[];
}

interface CviCategory {
  name: string;
  functions: CviFunction[];
  groups?: CviGroup[];
}

interface CviLibrary {
  name: string;
  categories: CviCategory[];
}

interface CviEnvironment {
  name: string;
  libraries: CviLibrary[];
}

interface CviDatabase {
  environments: CviEnvironment[];
  libraries: CviLibrary[];
}

interface LibraryPackFile {
  id?: string;
  name?: string;
  language?: string;
  version?: string;
  readOnly?: boolean;
  environments: CviEnvironment[];
  libraries?: CviLibrary[];
}

type PackSource = 'workspace' | 'global';

interface LoadedPack {
  id: string;
  name: string;
  language?: string;
  version?: string;
  readOnly?: boolean;
  environments: CviEnvironment[];
  libraries: CviLibrary[];
  filePath: string;
  source: PackSource;
  writable: boolean;
}

interface ExtensionData {
  db: CviDatabase;
  packs: LoadedPack[];
}


interface StoredFunctionState {
  values: string[];
  returnTarget: string;
}

interface WebviewMessage {
  type: 'insertCall' | 'copyCall' | 'pickValue' | 'persistState';
  text?: string;
  index?: number;
  editorType?: ParamEditorType;
  currentValue?: string;
  values?: string[];
  state?: StoredFunctionState;
}

interface PackEditorMessage {
  type: 'savePack' | 'openJson' | 'showInput' | 'showConfirm' | 'showPick' | 'runPackTool';
  pack?: LibraryPackFile;
  operation?: string;
  title?: string;
  prompt?: string;
  value?: string;
  placeHolder?: string;
  message?: string;
  confirmLabel?: string;
  payload?: any;
}


interface PickItemSpec {
  label: string;
  description?: string;
  detail?: string;
  value: string;
}

interface FunctionSearchEntry {
  fn: CviFunction;
  environment?: string;
  library: string;
  category: string;
}

interface FunctionQuickPickItem extends vscode.QuickPickItem {
  fn: CviFunction;
  entry: FunctionSearchEntry;
}

interface ResolvedParameter extends Omit<CviParameter, 'presets' | 'options'> {
  index: number;
  editorType: ParamEditorType;
  defaultValue: string;
  placeholder: string;
  presets: ChoiceSpec[];
  options: ChoiceSpec[];
}


type ImportedSymbolKind = 'function' | 'struct' | 'typedef' | 'enum' | 'enum_class' | 'class';
type SymbolKind = ImportedSymbolKind | 'keyword' | 'snippet' | 'table' | 'property' | 'variable' | 'reference' | 'method' | 'operator' | 'constant' | 'metamethod' | 'pitfall' | 'macro' | 'command' | 'concept' | 'attribute';

interface ParsedDocInfo {
  brief?: string;
  description?: string;
  longDescription?: string;
  returnDescription?: string;
  paramDescriptions?: Record<string, string>;
  notes?: string[];
  warnings?: string[];
}

interface ParsedImportedSymbol {
  kind: ImportedSymbolKind;
  name: string;
  declaration: string;
  returnType?: string;
  parameters?: CviParameter[];
  description?: string;
  longDescription?: string;
  returnDescription?: string;
  notes?: string[];
  warnings?: string[];
  fields?: CviStructField[];
  enumValues?: CviEnumValue[];
  methods?: CppMethod[];
  isStatic?: boolean;
}

const SYMBOL_CATEGORY_LABELS: Record<ImportedSymbolKind, string> = {
  function: 'Functions',
  struct: 'Structs',
  typedef: 'Typedefs',
  enum: 'Enums',
  enum_class: 'Enum Classes',
  class: 'Classes'
};

