    add({ category: 'Embedded & C Interop', name: 'opaque C handle implemented by C++ class', description: 'Back a stable C ABI handle with a private C++ implementation object.', insertText: `extern "C"
{
    struct DeviceHandle;

    struct DeviceConfig
    {
        std::uint32_t size;
        std::uint32_t baudRate;
    };

    int Device_Create(DeviceHandle **outHandle, const DeviceConfig *config);
    void Device_Destroy(DeviceHandle *handle);
}

class DeviceImpl
{
public:
    explicit DeviceImpl(std::uint32_t baudRate) : baudRate_(baudRate) {}
private:
    std::uint32_t baudRate_ = 0;
};

struct DeviceHandle
{
    DeviceImpl impl;

    explicit DeviceHandle(std::uint32_t baudRate)
        : impl(baudRate)
    {
    }
};` , longDescription: 'This pattern keeps the external ABI in C while still allowing the implementation to use constructors, RAII, templates, and the rest of C++. It is a common compromise for SDKs, plugins, and instrument drivers.' });
    add({ category: 'Embedded & C Interop', name: 'extern "C" factory with noexcept error boundary', description: 'Prevent exceptions from escaping across a C ABI or DLL boundary.', insertText: `extern "C" int Device_Create(DeviceHandle **outHandle, const DeviceConfig *config)
{
    if (!outHandle || !config)
    {
        return -1;
    }

    try
    {
        *outHandle = new DeviceHandle(config->baudRate);
        return 0;
    }
    catch (...)
    {
        *outHandle = nullptr;
        return -2;
    }
}

extern "C" void Device_Destroy(DeviceHandle *handle)
{
    delete handle;
}` , longDescription: 'Throwing across a C ABI is undefined territory in many real systems and is especially risky across shared-library boundaries compiled with different settings. Catch at the boundary and translate to explicit error codes.' });
    add({ category: 'Embedded & C Interop', name: 'error code + output buffer boundary pattern', description: 'Return status separately from produced data when exceptions and std::string are not ABI-safe.', insertText: `extern "C" int Device_GetLastErrorText(DeviceHandle *handle,
                                       char *buffer,
                                       std::size_t bufferSize)
{
    std::string message = LookupErrorText(handle);
    if (!buffer || bufferSize == 0)
    {
        return -1;
    }

    std::size_t count = std::min(bufferSize - 1, message.size());
    std::memcpy(buffer, message.data(), count);
    buffer[count] = '\0';
    return 0;
}` , longDescription: 'C ABIs should avoid returning std::string, exceptions, or allocator-owned memory unless ownership rules are extremely explicit. A caller-provided buffer keeps the lifetime model obvious and language-neutral.' });
    add({ category: 'Embedded & C Interop', name: 'size/version ABI negotiation', description: 'Accept older or newer struct layouts by checking size and version first.', insertText: `extern "C" int Device_OpenAdvanced(DeviceHandle *handle, const OpenOptions *options)
{
    if (!handle || !options)
    {
        return -1;
    }
    if (options->size < sizeof(std::uint32_t) * 2u)
    {
        return -2;
    }
    if (options->version != 1u)
    {
        return -3;
    }

    return 0;
}` , longDescription: 'Version-tagged option structures are a standard long-term ABI maintenance technique. They let a DLL evolve without forcing every consumer to rebuild immediately.' });
    add({ category: 'Embedded & C Interop', name: 'std::span<std::byte> over C buffer', description: 'Wrap a raw C pointer and length with a safer non-owning view in C++ code.', insertText: `#include <cstddef>
#include <span>

extern "C" int Device_Read(DeviceHandle *handle, void *buffer, std::size_t size);

std::span<std::byte> ReadFrame(DeviceHandle *handle, std::span<std::byte> storage)
{
    int count = Device_Read(handle, storage.data(), storage.size());
    if (count < 0)
    {
        return {};
    }
    return storage.first(static_cast<std::size_t>(count));
}` , longDescription: 'span is a good C++ adaptation layer on top of C buffers because it adds size information without taking ownership. It is particularly useful in protocol parsers, DMA wrappers, and binary APIs.' });
    add({ category: 'Industrial Patterns', name: 'driver HAL / service layering in C++', description: 'Separate hardware access, reusable protocol logic, and application orchestration.', insertText: `class IUartHal
{
public:
    virtual ~IUartHal() = default;
    virtual int Write(std::span<const std::byte> bytes) = 0;
    virtual int Read(std::span<std::byte> bytes) = 0;
};

class TelemetryService
{
public:
    explicit TelemetryService(IUartHal &uart) : uart_(uart) {}

    int SendPing()
    {
        const std::byte frame[] = { std::byte{0xAA}, std::byte{0x01}, std::byte{0x55} };
        return uart_.Write(frame);
    }

private:
    IUartHal &uart_;
};` , longDescription: 'Keeping the HAL narrow and the service logic independent from board code is one of the cleanest ways to obtain reusable protocol code, simulation hooks, and unit-test seams in C++ firmware and instrument control software.' });
    add({ category: 'Industrial Patterns', name: 'retry policy with bounded backoff', description: 'Retry transient hardware or transport faults without creating an infinite loop.', insertText: `template<typename Operation>
int RetryWithBackoff(Operation op, int maxAttempts)
{
    int delayMs = 10;
    for (int attempt = 1; attempt <= maxAttempts; ++attempt)
    {
        if (op() == 0)
        {
            return 0;
        }
        std::this_thread::sleep_for(std::chrono::milliseconds(delayMs));
        delayMs = std::min(delayMs * 2, 250);
    }
    return -1;
}` , longDescription: 'Hardware discovery, serial links, and field instruments often fail transiently. A bounded retry policy with explicit backoff is usually safer than duplicating ad hoc retry loops across the codebase.' });
    add({ category: 'Industrial Patterns', name: 'bench orchestrator with typed instruments', description: 'Coordinate several instruments through one high-level test sequence object.', insertText: `class IPowerSupply
{
public:
    virtual ~IPowerSupply() = default;
    virtual void SetVoltage(double volts) = 0;
};

class IDmm
{
public:
    virtual ~IDmm() = default;
    virtual double MeasureVoltage() = 0;
};

class BenchOrchestrator
{
public:
    BenchOrchestrator(IPowerSupply &psu, IDmm &dmm)
        : psu_(psu), dmm_(dmm)
    {
    }

    bool Check5V()
    {
        psu_.SetVoltage(5.0);
        return dmm_.MeasureVoltage() > 4.8;
    }

private:
    IPowerSupply &psu_;
    IDmm &dmm_;
};` , longDescription: 'A bench orchestrator expresses the test intent at a higher level than raw SCPI or driver calls. It makes sequencing, simulation, and reporting clearer in automated validation software.' });
    add({ category: 'Embedded & C Interop', name: 'exported C plugin descriptor from C++', description: 'Publish a versioned function table that a pure C host can consume safely.', insertText: `extern "C"
{
    struct PluginApi
    {
        std::uint32_t size;
        std::uint32_t version;
        int (*initialize)();
        int (*run_step)(int stepId);
        void (*shutdown)();
    };

    static int PluginInitialize() { return 0; }
    static int PluginRunStep(int stepId) { return stepId >= 0 ? 0 : -1; }
    static void PluginShutdown() {}

    const PluginApi *GetPluginApi()
    {
        static const PluginApi api{
            sizeof(PluginApi),
            1u,
            &PluginInitialize,
            &PluginRunStep,
            &PluginShutdown
        };
        return &api;
    }
}` , longDescription: 'A versioned exported function table is often simpler and more stable than exporting many unrelated symbols. Hosts can validate the descriptor once, then call through a narrow ABI that survives internal C++ refactoring.' });



