    add({ category: "Win32 Input & Hooks", name: "low-level keyboard hook", description: "Capture global keyboard activity with SetWindowsHookEx.", insertText: `HHOOK g_keyboardHook = NULL;

LRESULT CALLBACK LowLevelKeyboardProc(int nCode, WPARAM wParam, LPARAM lParam)
{
    if (nCode == HC_ACTION && wParam == WM_KEYDOWN)
    {
        const KBDLLHOOKSTRUCT *info = reinterpret_cast<const KBDLLHOOKSTRUCT *>(lParam);
        if (info->vkCode == VK_F8)
        {
            OutputDebugStringA("F8 pressed\n");
        }
    }
    return CallNextHookEx(g_keyboardHook, nCode, wParam, lParam);
}

g_keyboardHook = SetWindowsHookExA(WH_KEYBOARD_LL, LowLevelKeyboardProc, GetModuleHandle(NULL), 0);`, longDescription: "Useful for hotkeys, diagnostics overlays, and low-level input monitoring on Windows." });
