    add({ category: "Embedded GPIO & Timing", name: "software debounce", description: "Debounce a mechanical button with a time filter.", insertText: `typedef struct
{
    int stableState;
    int lastRawState;
    uint32_t lastChangeMs;
} DebounceState;

int DebounceUpdate(DebounceState *state, int rawState, uint32_t nowMs, uint32_t debounceMs)
{
    if (rawState != state->lastRawState)
    {
        state->lastRawState = rawState;
        state->lastChangeMs = nowMs;
    }

    if ((nowMs - state->lastChangeMs) >= debounceMs)
    {
        state->stableState = rawState;
    }

    return state->stableState;
}` , longDescription: "Debouncing is essential for buttons, limit switches, and relay contacts in embedded systems." });
    add({ category: "Embedded GPIO & Timing", name: "periodic tick scheduler", description: "Run periodic jobs from a millisecond tick without blocking delays.", insertText: `typedef struct
{
    uint32_t periodMs;
    uint32_t nextDeadline;
} PeriodicTask;

void RunPeriodicTask(PeriodicTask *task, uint32_t nowMs, void (*fn)(void))
{
    if ((int32_t)(nowMs - task->nextDeadline) >= 0)
    {
        task->nextDeadline += task->periodMs;
        fn();
    }
}` , longDescription: "A non-blocking periodic scheduler is often cleaner than stacking many delay calls in the main loop." });
