    add({ category: "Embedded Buses & Peripherals", name: "ADC moving average", description: "Smooth noisy ADC samples with a fixed-size moving average.", insertText: `#define ADC_AVG_COUNT 8

uint16_t FilterAdcSample(uint16_t sample)
{
    static uint16_t history[ADC_AVG_COUNT] = {0};
    static uint32_t sum = 0;
    static size_t index = 0;

    sum -= history[index];
    history[index] = sample;
    sum += sample;
    index = (index + 1) % ADC_AVG_COUNT;
    return (uint16_t)(sum / ADC_AVG_COUNT);
}` , longDescription: "A moving average is a simple first step for stabilizing sensors and analog measurements." });
    add({ category: "Embedded RTOS & ISR", name: "ring buffer from ISR", description: "Push UART bytes into a ring buffer from an interrupt.", insertText: `#define RX_BUFFER_SIZE 128
static volatile uint8_t rxBuffer[RX_BUFFER_SIZE];
static volatile uint16_t rxWrite = 0;
static volatile uint16_t rxRead = 0;

void UART_RxCallback(uint8_t byte)
{
    uint16_t next = (uint16_t)((rxWrite + 1u) % RX_BUFFER_SIZE);
    if (next != rxRead)
    {
        rxBuffer[rxWrite] = byte;
        rxWrite = next;
    }
}` , longDescription: "Ring buffers are extremely common in bare-metal serial receivers because they decouple ISR speed from parser speed." });
    add({ category: "Embedded RTOS & ISR", name: "consumer read from ring buffer", description: "Drain a ring buffer safely from the main loop or a task.", insertText: `int RingBufferReadByte(uint8_t *out)
{
    if (rxRead == rxWrite)
    {
        return 0;
    }

    *out = rxBuffer[rxRead];
    rxRead = (uint16_t)((rxRead + 1u) % RX_BUFFER_SIZE);
    return 1;
}` , longDescription: "Keep the ISR short, then parse bytes later in a task or cooperative loop." });
