    add({ category: "Embedded GPIO & Timing", name: "finite state machine", description: "Drive a peripheral or workflow with explicit states.", insertText: `typedef enum
{
    STATE_INIT,
    STATE_IDLE,
    STATE_ACTIVE,
    STATE_FAULT
} SystemState;

void RunStateMachine(SystemState *state)
{
    switch (*state)
    {
        case STATE_INIT: InitHardware(); *state = STATE_IDLE; break;
        case STATE_IDLE: if (StartCondition()) *state = STATE_ACTIVE; break;
        case STATE_ACTIVE: if (FaultDetected()) *state = STATE_FAULT; break;
        case STATE_FAULT: SafeShutdown(); break;
    }
}` , longDescription: "State machines are often the clearest way to organize embedded control logic." });
