    add({ category: "PyTorch Advanced AI", name: "Conv1D classifier module", description: "Build a compact 1D convolutional network for signals.", insertText: `import torch
from torch import nn

class SignalClassifier(nn.Module):
    def __init__(self, num_classes: int) -> None:
        super().__init__()
        self.features = nn.Sequential(
            nn.Conv1d(1, 16, kernel_size=7, padding=3),
            nn.ReLU(),
            nn.MaxPool1d(2),
            nn.Conv1d(16, 32, kernel_size=5, padding=2),
            nn.ReLU(),
            nn.AdaptiveAvgPool1d(1),
        )
        self.classifier = nn.Linear(32, num_classes)

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        x = self.features(x)
        x = x.squeeze(-1)
        return self.classifier(x)`, longDescription: "A small Conv1D model is a good baseline for time-series classification." });
    add({ category: "PyTorch Advanced AI", name: "training loop with scheduler", description: "Train with optimizer, scheduler, and validation loss tracking.", insertText: `import torch
from torch import nn

criterion = nn.CrossEntropyLoss()
optimizer = torch.optim.Adam(model.parameters(), lr=1e-3)
scheduler = torch.optim.lr_scheduler.ReduceLROnPlateau(optimizer, mode="min", patience=3)

for epoch in range(num_epochs):
    model.train()
    for inputs, labels in train_loader:
        inputs = inputs.to(device)
        labels = labels.to(device)
        optimizer.zero_grad(set_to_none=True)
        logits = model(inputs)
        loss = criterion(logits, labels)
        loss.backward()
        optimizer.step()

    scheduler.step(validation_loss)`, longDescription: "This is a practical baseline once a project needs more than the most minimal training loop." });
