    add({ category: "PyTorch Advanced AI", name: "custom Dataset for signal windows", description: "Expose signal windows through a Dataset class.", insertText: `import numpy as np
import torch
from torch.utils.data import Dataset

class SignalWindowDataset(Dataset):
    def __init__(self, X: np.ndarray, y: np.ndarray) -> None:
        self.X = torch.as_tensor(X, dtype=torch.float32)
        self.y = torch.as_tensor(y, dtype=torch.long)

    def __len__(self) -> int:
        return self.X.shape[0]

    def __getitem__(self, index: int):
        return self.X[index], self.y[index]`, longDescription: "A custom Dataset is the cleanest way to wrap precomputed windows and labels." });

