    add({ category: "OpenCV Advanced Vision & Calibration", name: "camera calibration from chessboard", description: "Estimate intrinsic parameters from calibration images.", insertText: `import cv2
import numpy as np

pattern_size = (9, 6)
object_points = []
image_points = []

objp = np.zeros((pattern_size[0] * pattern_size[1], 3), np.float32)
objp[:, :2] = np.mgrid[0:pattern_size[0], 0:pattern_size[1]].T.reshape(-1, 2)

for path in image_paths:
    image = cv2.imread(path)
    gray = cv2.cvtColor(image, cv2.COLOR_BGR2GRAY)
    found, corners = cv2.findChessboardCorners(gray, pattern_size)
    if found:
        object_points.append(objp)
        image_points.append(corners)

ret, camera_matrix, dist_coeffs, rvecs, tvecs = cv2.calibrateCamera(object_points, image_points, gray.shape[::-1], None, None)`, longDescription: "Camera calibration is fundamental for metric vision, robotics, and distortion correction." });
    add({ category: "OpenCV Advanced Vision & Calibration", name: "solvePnP pose estimate", description: "Estimate object pose from 2D-3D correspondences.", insertText: `import cv2
import numpy as np

success, rvec, tvec = cv2.solvePnP(
    object_points_3d,
    image_points_2d,
    camera_matrix,
    dist_coeffs,
)
if success:
    print(rvec.ravel(), tvec.ravel())`, longDescription: "solvePnP is one of the standard baselines for pose estimation." });
    add({ category: "ONNX Runtime Optimization & Deployment", name: "execution providers selection", description: "Choose providers explicitly for an ONNX Runtime session.", insertText: `import onnxruntime as ort

providers = ["CUDAExecutionProvider", "CPUExecutionProvider"]
session = ort.InferenceSession("model.onnx", providers=providers)
print(session.get_providers())`, longDescription: "Explicit provider ordering is useful when deployment targets may or may not expose GPU acceleration." });
    add({ category: "MLOps & Experiment Tracking", name: "seed everything helper", description: "Set deterministic seeds for common ML libraries.", insertText: `import os
import random
import numpy as np
import torch

seed = 42
os.environ["PYTHONHASHSEED"] = str(seed)
random.seed(seed)
np.random.seed(seed)
torch.manual_seed(seed)
torch.cuda.manual_seed_all(seed)`, longDescription: "A global seeding helper is a standard first step when comparing experiments." });
    add({ category: "MLOps & Experiment Tracking", name: "MLflow log metrics and artifacts", description: "Track metrics and save an artifact with MLflow.", insertText: `import mlflow

with mlflow.start_run():
    mlflow.log_param("model", "SignalNet")
    mlflow.log_metric("val_accuracy", float(val_accuracy))
    mlflow.log_artifact("best_model.pt")`, longDescription: "MLflow is a common baseline when experiment tracking needs to grow beyond ad-hoc text logs." });
    add({ category: "Scientific Instrumentation Advanced", name: "pyserial framed transaction", description: "Write a frame and wait for a delimited reply.", insertText: `import serial

with serial.Serial("COM3", baudrate=115200, timeout=1.0) as port:
    port.write(b"MEAS?\r\n")
    reply = port.readline().decode("ascii", errors="replace").strip()
    print(reply)`, longDescription: "A framed request-reply pattern is the baseline for many UART bench tools." });
    add({ category: "Scientific Instrumentation Advanced", name: "pyvisa SCPI acquisition", description: "Open an instrument and query a measurement.", insertText: `import pyvisa

rm = pyvisa.ResourceManager()
with rm.open_resource("TCPIP0::192.168.0.10::inst0::INSTR") as inst:
    inst.write("*RST")
    value = inst.query("MEAS:VOLT:DC?")
    print(value)`, longDescription: "SCPI over VISA is common when automating lab instruments from Python." });
    add({ category: "Scientific Instrumentation Advanced", name: "memory-mapped binary capture", description: "Read large binary captures without loading everything eagerly.", insertText: `import numpy as np

capture = np.memmap("capture.bin", dtype=np.int16, mode="r")
segment = capture[start_index:start_index + 100000]`, longDescription: "memmap is useful when working with very large acquisition files." });
    add({ category: "Signal Processing Research Patterns", name: "coherence estimate", description: "Estimate linear correlation in the frequency domain.", insertText: `from scipy import signal

frequencies_hz, coherence = signal.coherence(x, y, fs=sample_rate_hz, nperseg=1024)`, longDescription: "Magnitude-squared coherence is useful when comparing measured input and output channels." });
    add({ category: "Signal Processing Research Patterns", name: "transfer function estimate H1", description: "Estimate a simple frequency response from cross spectra.", insertText: `from scipy import signal
import numpy as np

frequencies_hz, Pxy = signal.csd(input_signal, output_signal, fs=sample_rate_hz, nperseg=1024)
_, Pxx = signal.welch(input_signal, fs=sample_rate_hz, nperseg=1024)

H1 = Pxy / Pxx
magnitude_db = 20.0 * np.log10(np.abs(H1))
phase_deg = np.unwrap(np.angle(H1)) * 180.0 / np.pi`, longDescription: "A basic H1 estimate is a good starting point in system-identification exercises." });
    add({ category: "Signal Processing Research Patterns", name: "wavelet denoising baseline", description: "Denoise a waveform with wavelets.", insertText: `import pywt
import numpy as np

coeffs = pywt.wavedec(signal_values, wavelet="db4", level=4)
sigma = np.median(np.abs(coeffs[-1])) / 0.6745
threshold = sigma * np.sqrt(2.0 * np.log(len(signal_values)))
coeffs[1:] = [pywt.threshold(c, threshold, mode="soft") for c in coeffs[1:]]
denoised = pywt.waverec(coeffs, wavelet="db4")`, longDescription: "Wavelet denoising is a useful alternative to purely frequency-domain filtering." });


    add({ category: "Python GUI Tkinter Basics", name: "tkinter main window", description: "Create a minimal Tkinter application window.", insertText: "import tkinter as tk\n\nroot = tk.Tk()\nroot.title(\"Signal Tool\")\nroot.geometry(\"900x600\")\n\nroot.mainloop()", longDescription: "Tkinter is part of the standard library and remains useful for small internal tools, quick signal-processing frontends, and configuration utilities." });
    add({ category: "Python GUI Tkinter Basics", name: "button callback", description: "Create a Tkinter button connected to a callback.", insertText: "import tkinter as tk\n\nroot = tk.Tk()\n\ndef on_compute() -> None:\n    print(\"Compute clicked\")\n\nbutton = tk.Button(root, text=\"Compute\", command=on_compute)\nbutton.pack(padx=12, pady=12)\n\nroot.mainloop()", longDescription: "Tkinter widgets usually connect actions through the command parameter for simple callbacks." });
    add({ category: "Python GUI Tkinter Basics", name: "entry + label + callback", description: "Read an Entry value and update a Label.", insertText: "import tkinter as tk\n\nroot = tk.Tk()\n\nentry = tk.Entry(root)\nentry.pack(padx=8, pady=8)\nstatus = tk.Label(root, text=\"Ready\")\nstatus.pack(padx=8, pady=8)\n\ndef on_apply() -> None:\n    status.config(text=f\"Value: {entry.get()}\")\n\ntk.Button(root, text=\"Apply\", command=on_apply).pack(padx=8, pady=8)\n\nroot.mainloop()", longDescription: "A practical baseline for parameter entry dialogs and small bench tools." });
    add({ category: "Python GUI Tkinter Basics", name: "variable binding StringVar", description: "Bind widget state through a Tkinter variable.", insertText: "import tkinter as tk\n\nroot = tk.Tk()\nselected_mode = tk.StringVar(value=\"FFT\")\n\nmode_menu = tk.OptionMenu(root, selected_mode, \"FFT\", \"Filter\", \"Train\")\nmode_menu.pack(padx=8, pady=8)\n\ndef on_show() -> None:\n    print(selected_mode.get())\n\ntk.Button(root, text=\"Show mode\", command=on_show).pack(padx=8, pady=8)\n\nroot.mainloop()", longDescription: "Tk variables simplify synchronization between widgets and application state." });
    add({ category: "Python GUI Tkinter Layout & Widgets", name: "grid layout form", description: "Build a simple form using grid layout.", insertText: "import tkinter as tk\nfrom tkinter import ttk\n\nroot = tk.Tk()\nroot.columnconfigure(1, weight=1)\n\nttk.Label(root, text=\"Sample rate\").grid(row=0, column=0, padx=8, pady=4, sticky=\"w\")\nfs_entry = ttk.Entry(root)\nfs_entry.grid(row=0, column=1, padx=8, pady=4, sticky=\"ew\")\n\nttk.Label(root, text=\"Cutoff\").grid(row=1, column=0, padx=8, pady=4, sticky=\"w\")\nfc_entry = ttk.Entry(root)\nfc_entry.grid(row=1, column=1, padx=8, pady=4, sticky=\"ew\")\n\nroot.mainloop()", longDescription: "grid is often the cleanest layout manager for parameter panels and engineering dialogs." });
    add({ category: "Python GUI Tkinter Layout & Widgets", name: "ttk notebook tabs", description: "Create a tabbed interface with ttk.Notebook.", insertText: "import tkinter as tk\nfrom tkinter import ttk\n\nroot = tk.Tk()\nnotebook = ttk.Notebook(root)\nnotebook.pack(fill=\"both\", expand=True)\n\nsignal_tab = ttk.Frame(notebook)\nmodel_tab = ttk.Frame(notebook)\nnotebook.add(signal_tab, text=\"Signal\")\nnotebook.add(model_tab, text=\"Model\")\n\nttk.Label(signal_tab, text=\"Signal tools\").pack(padx=12, pady=12)\nttk.Label(model_tab, text=\"AI tools\").pack(padx=12, pady=12)\n\nroot.mainloop()", longDescription: "Notebook tabs help separate acquisition, signal processing, and model-training workflows." });
    add({ category: "Python GUI Tkinter Layout & Widgets", name: "treeview table", description: "Display tabular data with ttk.Treeview.", insertText: "import tkinter as tk\nfrom tkinter import ttk\n\nroot = tk.Tk()\ntree = ttk.Treeview(root, columns=(\"channel\", \"rms\"), show=\"headings\")\ntree.heading(\"channel\", text=\"Channel\")\ntree.heading(\"rms\", text=\"RMS\")\ntree.pack(fill=\"both\", expand=True)\n\nfor row in [(\"CH1\", 1.24), (\"CH2\", 0.98)]:\n    tree.insert(\"\", \"end\", values=row)\n\nroot.mainloop()", longDescription: "Treeview is useful for quick tables, result lists, and signal feature summaries." });
    add({ category: "Python GUI Tkinter Layout & Widgets", name: "file dialog", description: "Open a file chooser from Tkinter.", insertText: "import tkinter as tk\nfrom tkinter import filedialog\n\nroot = tk.Tk()\nroot.withdraw()\npath = filedialog.askopenfilename(title=\"Open signal\", filetypes=[(\"CSV\", \"*.csv\"), (\"All files\", \"*.*\")])\nprint(path)", longDescription: "Useful for selecting datasets, configuration files, or trained models." });
    add({ category: "Python GUI Tkinter Canvas & Events", name: "canvas line plot", description: "Draw a simple polyline on a Tkinter Canvas.", insertText: "import tkinter as tk\n\nroot = tk.Tk()\ncanvas = tk.Canvas(root, width=600, height=240, bg=\"white\")\ncanvas.pack(fill=\"both\", expand=True)\n\npoints = [10, 120, 80, 40, 160, 180, 240, 90, 320, 140]\ncanvas.create_line(points, fill=\"blue\", width=2, smooth=False)\n\nroot.mainloop()", longDescription: "Canvas is enough for many lightweight engineering visualizations when full plotting libraries are unnecessary." });
    add({ category: "Python GUI Tkinter Canvas & Events", name: "bind mouse motion", description: "Track pointer motion on a widget.", insertText: "import tkinter as tk\n\nroot = tk.Tk()\nlabel = tk.Label(root, text=\"Move the mouse\")\nlabel.pack(padx=8, pady=8)\n\ndef on_motion(event: tk.Event) -> None:\n    label.config(text=f\"x={event.x} y={event.y}\")\n\nroot.bind(\"<Motion>\", on_motion)\nroot.mainloop()", longDescription: "Event binding is the Tkinter equivalent of wiring callbacks for input events." });
    add({ category: "Python GUI Tkinter Canvas & Events", name: "after periodic refresh", description: "Refresh GUI content periodically with after().", insertText: "import tkinter as tk\nimport random\n\nroot = tk.Tk()\nvalue_label = tk.Label(root, text=\"0.0\")\nvalue_label.pack(padx=8, pady=8)\n\ndef refresh() -> None:\n    value_label.config(text=f\"{random.random():.3f}\")\n    root.after(200, refresh)\n\nrefresh()\nroot.mainloop()", longDescription: "after is the standard Tkinter mechanism for timers and periodic acquisition refresh." });
    add({ category: "Python GUI PySide6 / PyQt6 Widgets", name: "QApplication + QWidget", description: "Create a minimal Qt widget application in Python.", insertText: "import sys\nfrom PySide6.QtWidgets import QApplication, QLabel, QVBoxLayout, QWidget\n\napp = QApplication(sys.argv)\nwindow = QWidget()\nwindow.setWindowTitle(\"Signal Tool\")\nlayout = QVBoxLayout(window)\nlayout.addWidget(QLabel(\"Hello Qt for Python\"))\nwindow.resize(900, 600)\nwindow.show()\nraise SystemExit(app.exec())", longDescription: "PySide6 and PyQt6 are strong choices when a Python GUI needs a more capable widget toolkit than Tkinter." });
    add({ category: "Python GUI PySide6 / PyQt6 Widgets", name: "QPushButton callback method", description: "Connect a QPushButton clicked signal to a method.", insertText: "import sys\nfrom PySide6.QtWidgets import QApplication, QPushButton, QVBoxLayout, QWidget\n\nclass MainWindow(QWidget):\n    def __init__(self) -> None:\n        super().__init__()\n        layout = QVBoxLayout(self)\n        button = QPushButton(\"Compute\")\n        button.clicked.connect(self.on_compute_clicked)\n        layout.addWidget(button)\n\n    def on_compute_clicked(self) -> None:\n        print(\"Compute clicked\")\n\napp = QApplication(sys.argv)\nwindow = MainWindow()\nwindow.show()\nraise SystemExit(app.exec())", longDescription: "This is the closest Python equivalent to wiring a button callback in many desktop GUI frameworks." });
    add({ category: "Python GUI PySide6 / PyQt6 Widgets", name: "signal to lambda", description: "Connect a Qt signal to a lambda for short actions.", insertText: "import sys\nfrom PySide6.QtWidgets import QApplication, QLabel, QPushButton, QVBoxLayout, QWidget\n\napp = QApplication(sys.argv)\nwindow = QWidget()\nlayout = QVBoxLayout(window)\nstatus = QLabel(\"Ready\")\nbutton = QPushButton(\"Run\")\nbutton.clicked.connect(lambda: status.setText(\"Running\"))\nlayout.addWidget(status)\nlayout.addWidget(button)\nwindow.show()\nraise SystemExit(app.exec())", longDescription: "Small UI reactions are often concise with lambdas, while larger logic should remain in dedicated methods." });
    add({ category: "Python GUI PySide6 / PyQt6 Widgets", name: "QMainWindow with toolbar and status bar", description: "Create a QMainWindow shell for a desktop tool.", insertText: "import sys\nfrom PySide6.QtGui import QAction\nfrom PySide6.QtWidgets import QApplication, QLabel, QMainWindow, QStatusBar, QToolBar\n\nclass MainWindow(QMainWindow):\n    def __init__(self) -> None:\n        super().__init__()\n        self.setWindowTitle(\"DSP Workbench\")\n        self.setCentralWidget(QLabel(\"Central widget\"))\n\n        toolbar = QToolBar(\"Main\")\n        self.addToolBar(toolbar)\n\n        action_open = QAction(\"Open\", self)\n        action_open.triggered.connect(self.on_open)\n        toolbar.addAction(action_open)\n\n        self.setStatusBar(QStatusBar(self))\n        self.statusBar().showMessage(\"Ready\")\n\n    def on_open(self) -> None:\n        self.statusBar().showMessage(\"Open clicked\")\n\napp = QApplication(sys.argv)\nwindow = MainWindow()\nwindow.resize(1100, 700)\nwindow.show()\nraise SystemExit(app.exec())", longDescription: "QMainWindow is the standard shell for complex Python desktop applications with menus, toolbars, and dockable panels." });
    add({ category: "Python GUI PySide6 / PyQt6 Widgets", name: "form inputs and callback", description: "Read form fields when a button is clicked.", insertText: "import sys\nfrom PySide6.QtWidgets import QApplication, QDoubleSpinBox, QFormLayout, QPushButton, QVBoxLayout, QWidget\n\nclass MainWindow(QWidget):\n    def __init__(self) -> None:\n        super().__init__()\n        layout = QVBoxLayout(self)\n        form = QFormLayout()\n        self.fs_spin = QDoubleSpinBox()\n        self.fs_spin.setValue(1000.0)\n        self.fc_spin = QDoubleSpinBox()\n        self.fc_spin.setValue(50.0)\n        form.addRow(\"Fs\", self.fs_spin)\n        form.addRow(\"Fc\", self.fc_spin)\n        layout.addLayout(form)\n\n        run_button = QPushButton(\"Apply\")\n        run_button.clicked.connect(self.on_apply)\n        layout.addWidget(run_button)\n\n    def on_apply(self) -> None:\n        print(self.fs_spin.value(), self.fc_spin.value())\n\napp = QApplication(sys.argv)\nwindow = MainWindow()\nwindow.show()\nraise SystemExit(app.exec())", longDescription: "A common pattern for control panels and DSP parameter editors." });
    add({ category: "Python GUI PySide6 / PyQt6 Designer & UI Files", name: "load ui class generated by pyside6-uic", description: "Use a Ui_* class generated from a .ui file.", insertText: "import sys\nfrom PySide6.QtWidgets import QApplication, QMainWindow\nfrom ui_mainwindow import Ui_MainWindow\n\nclass MainWindow(QMainWindow):\n    def __init__(self) -> None:\n        super().__init__()\n        self.ui = Ui_MainWindow()\n        self.ui.setupUi(self)\n        self.ui.pushButtonCompute.clicked.connect(self.on_compute)\n\n    def on_compute(self) -> None:\n        self.ui.statusbar.showMessage(\"Compute clicked\")\n\napp = QApplication(sys.argv)\nwindow = MainWindow()\nwindow.show()\nraise SystemExit(app.exec())", longDescription: "This is the usual pattern when Qt Designer generates a Python UI class for your form." });
    add({ category: "Python GUI PySide6 / PyQt6 Designer & UI Files", name: "QUiLoader runtime ui loading", description: "Load a .ui file at runtime and wire signals manually.", insertText: "import sys\nfrom pathlib import Path\nfrom PySide6.QtCore import QFile\nfrom PySide6.QtUiTools import QUiLoader\nfrom PySide6.QtWidgets import QApplication\n\napp = QApplication(sys.argv)\nloader = QUiLoader()\nui_file = QFile(str(Path(\"mainwindow.ui\")))\nui_file.open(QFile.ReadOnly)\nwindow = loader.load(ui_file)\nui_file.close()\n\nbutton = window.findChild(type(window.findChild), \"pushButtonCompute\")\n# Better: use QWidget subclasses directly when available, e.g. QPushButton\nwindow.show()\nraise SystemExit(app.exec())", longDescription: "Runtime loading is useful when forms should remain editable without regenerating Python code." });
    add({ category: "Python GUI PySide6 / PyQt6 Designer & UI Files", name: "findChild on designer widget", description: "Find a widget created in a .ui file by objectName.", insertText: "from PySide6.QtWidgets import QPushButton\n\nbutton = self.findChild(QPushButton, \"pushButtonCompute\")\nif button is not None:\n    button.clicked.connect(self.on_compute)", longDescription: "findChild is useful when a widget comes from Designer and you need to access it by name at runtime." });
    add({ category: "Python GUI PySide6 / PyQt6 Designer & UI Files", name: "auto-connect style slot name", description: "Example slot name matching a Designer object and signal.", insertText: "from PySide6.QtCore import Slot\n\n@Slot()\ndef on_pushButtonCompute_clicked(self) -> None:\n    print(\"Designer button clicked\")", longDescription: "Keeping slot names aligned with Designer object names can simplify UI wiring conventions." });
    add({ category: "Python GUI PySide6 / PyQt6 Painting, Images & Multimedia", name: "custom paintEvent with QPainter", description: "Draw custom content inside a QWidget.", insertText: "import sys\nfrom PySide6.QtCore import QPoint\nfrom PySide6.QtGui import QPainter, QPen\nfrom PySide6.QtWidgets import QApplication, QWidget\n\nclass PlotWidget(QWidget):\n    def paintEvent(self, event) -> None:\n        painter = QPainter(self)\n        painter.setRenderHint(QPainter.Antialiasing)\n        painter.setPen(QPen())\n        points = [QPoint(10, 120), QPoint(80, 40), QPoint(160, 180), QPoint(240, 90)]\n        for p0, p1 in zip(points, points[1:]):\n            painter.drawLine(p0, p1)\n\napp = QApplication(sys.argv)\nwindow = PlotWidget()\nwindow.resize(600, 300)\nwindow.show()\nraise SystemExit(app.exec())", longDescription: "Custom painting is appropriate for lightweight signal traces, overlays, and instrument-style widgets." });
    add({ category: "Python GUI PySide6 / PyQt6 Painting, Images & Multimedia", name: "display image in QLabel", description: "Load and display an image with QPixmap.", insertText: "import sys\nfrom PySide6.QtGui import QPixmap\nfrom PySide6.QtWidgets import QApplication, QLabel\n\napp = QApplication(sys.argv)\nlabel = QLabel()\nlabel.setPixmap(QPixmap(\"image.png\"))\nlabel.show()\nraise SystemExit(app.exec())", longDescription: "A QLabel with QPixmap is often enough for image display in engineering tools and quick viewers." });
    add({ category: "Python GUI PySide6 / PyQt6 Painting, Images & Multimedia", name: "QGraphicsView image scene", description: "Display an image in a QGraphicsScene/QGraphicsView.", insertText: "import sys\nfrom PySide6.QtGui import QPixmap\nfrom PySide6.QtWidgets import QApplication, QGraphicsPixmapItem, QGraphicsScene, QGraphicsView\n\napp = QApplication(sys.argv)\nscene = QGraphicsScene()\nscene.addItem(QGraphicsPixmapItem(QPixmap(\"image.png\")))\nview = QGraphicsView(scene)\nview.show()\nraise SystemExit(app.exec())", longDescription: "Graphics View is useful when zoom, pan, overlays, or multiple items are needed." });
    add({ category: "Python GUI PySide6 / PyQt6 Painting, Images & Multimedia", name: "play sound with QSoundEffect", description: "Play a short sound effect from a Qt GUI.", insertText: "import sys\nfrom pathlib import Path\nfrom PySide6.QtCore import QUrl\nfrom PySide6.QtMultimedia import QSoundEffect\nfrom PySide6.QtWidgets import QApplication, QPushButton\n\napp = QApplication(sys.argv)\nsound = QSoundEffect()\nsound.setSource(QUrl.fromLocalFile(str(Path(\"click.wav\").resolve())))\nbutton = QPushButton(\"Play\")\nbutton.clicked.connect(sound.play)\nbutton.show()\nraise SystemExit(app.exec())", longDescription: "QSoundEffect is a simple solution for short UI or event sounds." });
    add({ category: "Python GUI PySide6 / PyQt6 Painting, Images & Multimedia", name: "audio playback with QMediaPlayer", description: "Play an audio file from a Qt GUI.", insertText: "import sys\nfrom pathlib import Path\nfrom PySide6.QtCore import QUrl\nfrom PySide6.QtMultimedia import QAudioOutput, QMediaPlayer\nfrom PySide6.QtWidgets import QApplication, QPushButton\n\napp = QApplication(sys.argv)\naudio_output = QAudioOutput()\nplayer = QMediaPlayer()\nplayer.setAudioOutput(audio_output)\nplayer.setSource(QUrl.fromLocalFile(str(Path(\"audio.wav\").resolve())))\nbutton = QPushButton(\"Play audio\")\nbutton.clicked.connect(player.play)\nbutton.show()\nraise SystemExit(app.exec())", longDescription: "QMediaPlayer handles longer audio playback and integrates cleanly into Qt applications." });
    add({ category: "Python GUI PySide6 / PyQt6 Painting, Images & Multimedia", name: "camera preview with QCamera", description: "Preview a camera stream in a Qt widget.", insertText: "import sys\nfrom PySide6.QtMultimedia import QCamera, QMediaCaptureSession\nfrom PySide6.QtMultimediaWidgets import QVideoWidget\nfrom PySide6.QtWidgets import QApplication\n\napp = QApplication(sys.argv)\nvideo_widget = QVideoWidget()\nvideo_widget.resize(800, 600)\nvideo_widget.show()\n\ncamera = QCamera()\nsession = QMediaCaptureSession()\nsession.setCamera(camera)\nsession.setVideoOutput(video_widget)\ncamera.start()\n\nraise SystemExit(app.exec())", longDescription: "Very useful for camera tools, vision demos, and lab setups mixing acquisition with a GUI." });
    add({ category: "Python GUI Plotting & Scientific UI", name: "matplotlib embedded in Tkinter", description: "Embed a Matplotlib figure inside a Tkinter application.", insertText: "import tkinter as tk\nimport numpy as np\nfrom matplotlib.backends.backend_tkagg import FigureCanvasTkAgg\nfrom matplotlib.figure import Figure\n\nroot = tk.Tk()\nfigure = Figure(figsize=(6, 3), dpi=100)\naxes = figure.add_subplot(111)\nx = np.linspace(0.0, 1.0, 500)\naxes.plot(x, np.sin(2.0 * np.pi * 10.0 * x))\ncanvas = FigureCanvasTkAgg(figure, master=root)\ncanvas.draw()\ncanvas.get_tk_widget().pack(fill=\"both\", expand=True)\nroot.mainloop()", longDescription: "Embedding Matplotlib is one of the most practical ways to add scientific plotting to Python GUIs." });
    add({ category: "Python GUI Plotting & Scientific UI", name: "matplotlib embedded in PySide6", description: "Embed a Matplotlib figure inside a Qt window.", insertText: "import sys\nimport numpy as np\nfrom matplotlib.backends.backend_qtagg import FigureCanvasQTAgg\nfrom matplotlib.figure import Figure\nfrom PySide6.QtWidgets import QApplication, QVBoxLayout, QWidget\n\nclass MainWindow(QWidget):\n    def __init__(self) -> None:\n        super().__init__()\n        layout = QVBoxLayout(self)\n        figure = Figure()\n        canvas = FigureCanvasQTAgg(figure)\n        axes = figure.add_subplot(111)\n        x = np.linspace(0.0, 1.0, 500)\n        axes.plot(x, np.cos(2.0 * np.pi * 5.0 * x))\n        layout.addWidget(canvas)\n\napp = QApplication(sys.argv)\nwindow = MainWindow()\nwindow.resize(900, 500)\nwindow.show()\nraise SystemExit(app.exec())", longDescription: "Qt + Matplotlib is a strong combination for signal-processing tools and analysis GUIs." });
    add({ category: "Python GUI Plotting & Scientific UI", name: "pyqtgraph realtime curve", description: "Plot rapidly updating data with pyqtgraph.", insertText: "import sys\nimport numpy as np\nimport pyqtgraph as pg\nfrom PySide6.QtCore import QTimer\nfrom PySide6.QtWidgets import QApplication\n\napp = QApplication(sys.argv)\nplot = pg.plot(title=\"Realtime\")\ncurve = plot.plot(pen=\"y\")\n\nphase = 0.0\ndef update() -> None:\n    global phase\n    x = np.linspace(0.0, 1.0, 500)\n    y = np.sin(2.0 * np.pi * 5.0 * x + phase)\n    curve.setData(x, y)\n    phase += 0.2\n\ntimer = QTimer()\ntimer.timeout.connect(update)\ntimer.start(50)\nplot.show()\nraise SystemExit(app.exec())", longDescription: "pyqtgraph is especially effective for fast, interactive waveform displays in Python." });
    add({ category: "Python GUI Plotting & Scientific UI", name: "OpenCV image in Qt label", description: "Convert an OpenCV image to QImage/QPixmap for display.", insertText: "import sys\nimport cv2\nfrom PySide6.QtGui import QImage, QPixmap\nfrom PySide6.QtWidgets import QApplication, QLabel\n\nframe = cv2.imread(\"image.png\")\nrgb = cv2.cvtColor(frame, cv2.COLOR_BGR2RGB)\nheight, width, channels = rgb.shape\nbytes_per_line = channels * width\nimage = QImage(rgb.data, width, height, bytes_per_line, QImage.Format_RGB888)\n\napp = QApplication(sys.argv)\nlabel = QLabel()\nlabel.setPixmap(QPixmap.fromImage(image))\nlabel.show()\nraise SystemExit(app.exec())", longDescription: "A standard bridge when a vision pipeline is computed in OpenCV but displayed in a Qt GUI." });
    add({ category: "Python GUI Async, Threads & Background Work", name: "Tkinter worker queue", description: "Run background work and update Tkinter through a queue.", insertText: "import queue\nimport threading\nimport time\nimport tkinter as tk\n\nroot = tk.Tk()\nstatus = tk.Label(root, text=\"Idle\")\nstatus.pack(padx=8, pady=8)\nmessages: queue.Queue[str] = queue.Queue()\n\ndef worker() -> None:\n    time.sleep(1.0)\n    messages.put(\"Done\")\n\ndef poll_queue() -> None:\n    try:\n        status.config(text=messages.get_nowait())\n    except queue.Empty:\n        pass\n    root.after(100, poll_queue)\n\ndef on_start() -> None:\n    status.config(text=\"Running\")\n    threading.Thread(target=worker, daemon=True).start()\n\ntk.Button(root, text=\"Start\", command=on_start).pack(padx=8, pady=8)\npoll_queue()\nroot.mainloop()", longDescription: "Tkinter widgets should be updated from the GUI thread; a queue plus after() is a safe pattern." });
    add({ category: "Python GUI Async, Threads & Background Work", name: "QThread worker object", description: "Move a worker QObject to a QThread and report results.", insertText: "import sys\nfrom PySide6.QtCore import QObject, QThread, Signal, Slot\nfrom PySide6.QtWidgets import QApplication, QLabel, QPushButton, QVBoxLayout, QWidget\n\nclass Worker(QObject):\n    finished = Signal(float)\n\n    @Slot()\n    def run(self) -> None:\n        result = 42.0\n        self.finished.emit(result)\n\nclass MainWindow(QWidget):\n    def __init__(self) -> None:\n        super().__init__()\n        self.label = QLabel(\"Idle\")\n        button = QPushButton(\"Start\")\n        button.clicked.connect(self.start_worker)\n        layout = QVBoxLayout(self)\n        layout.addWidget(self.label)\n        layout.addWidget(button)\n        self.thread: QThread | None = None\n        self.worker: Worker | None = None\n\n    def start_worker(self) -> None:\n        self.thread = QThread()\n        self.worker = Worker()\n        self.worker.moveToThread(self.thread)\n        self.thread.started.connect(self.worker.run)\n        self.worker.finished.connect(self.on_finished)\n        self.worker.finished.connect(self.thread.quit)\n        self.thread.start()\n\n    def on_finished(self, value: float) -> None:\n        self.label.setText(f\"Result: {value}\")\n\napp = QApplication(sys.argv)\nwindow = MainWindow()\nwindow.show()\nraise SystemExit(app.exec())", longDescription: "This is the canonical Qt pattern for non-blocking computations from Python GUIs." });
    add({ category: "Python GUI Async, Threads & Background Work", name: "QTimer periodic acquisition", description: "Poll or acquire data periodically with QTimer.", insertText: "import sys\nfrom PySide6.QtCore import QTimer\nfrom PySide6.QtWidgets import QApplication, QLabel\n\napp = QApplication(sys.argv)\nlabel = QLabel(\"0\")\nlabel.show()\ncount = 0\n\ndef update() -> None:\n    global count\n    count += 1\n    label.setText(str(count))\n\ntimer = QTimer()\ntimer.timeout.connect(update)\ntimer.start(100)\nraise SystemExit(app.exec())", longDescription: "QTimer is appropriate for UI refresh, acquisition loops, and periodic background polling." });

