    add({ category: "Python Backend APIs", name: "FastAPI WebSocket broadcast", description: "Keep a small list of websocket clients and broadcast messages.", insertText: `from fastapi import FastAPI, WebSocket

app = FastAPI()
clients: list[WebSocket] = []


@app.websocket("/ws")
async def websocket_endpoint(websocket: WebSocket) -> None:
    await websocket.accept()
    clients.append(websocket)
    try:
        while True:
            message = await websocket.receive_text()
            for client in list(clients):
                await client.send_text(message)
    finally:
        if websocket in clients:
            clients.remove(websocket)` , longDescription: "A practical baseline for dashboards, bench frontends, and monitoring tools that need push updates." });
