    add({ category: "Python Automation & Operations", name: "retry with exponential backoff", description: "Retry a fragile operation before failing.", insertText: `import time
from collections.abc import Callable
from typing import TypeVar

T = TypeVar("T")

def retry(operation: Callable[[], T], attempts: int = 5, delay_s: float = 0.2) -> T:
    for attempt in range(attempts):
        try:
            return operation()
        except Exception:
            if attempt == attempts - 1:
                raise
            time.sleep(delay_s * (2 ** attempt))
    raise RuntimeError("unreachable")` , longDescription: "A small retry helper is often enough for network calls, devices, and flaky startup sequences." });
    add({ category: "Python Automation & Operations", name: "JSON structured logging", description: "Emit machine-readable logs for services and tools.", insertText: `import json
import logging
import sys

class JsonFormatter(logging.Formatter):
    def format(self, record: logging.LogRecord) -> str:
        payload = {
            "level": record.levelname,
            "name": record.name,
            "message": record.getMessage(),
        }
        return json.dumps(payload)

handler = logging.StreamHandler(sys.stdout)
handler.setFormatter(JsonFormatter())
logger = logging.getLogger("app")
logger.setLevel(logging.INFO)
logger.addHandler(handler)
logger.info("started")` , longDescription: "Structured logs are easier to filter and aggregate in backend or production tooling." });
