    add({ category: "Python Realtime Acquisition & Bench Patterns", name: "producer consumer queue", description: "Move acquired samples from a worker to a processor thread.", insertText: `from queue import Queue
from threading import Thread

queue: Queue[list[float]] = Queue()

def producer() -> None:
    for _ in range(10):
        queue.put([0.1, 0.2, 0.3])
    queue.put([])


def consumer() -> None:
    while True:
        block = queue.get()
        if not block:
            break
        print(sum(block))

Thread(target=producer, daemon=True).start()
Thread(target=consumer, daemon=True).start()` , longDescription: "Queues are a simple and safe bridge between acquisition and processing stages." });
