    add({ category: "Python Lab Automation & Calibration Advanced", name: "limits with guard bands", description: "Apply pass/fail thresholds with a guard band.", insertText: `from dataclasses import dataclass

@dataclass(slots=True)
class Limit:
    lower: float
    upper: float
    guard_band: float = 0.0

    def check(self, value: float) -> bool:
        return (self.lower + self.guard_band) <= value <= (self.upper - self.guard_band)

limit = Limit(4.9, 5.1, guard_band=0.01)
print(limit.check(5.0))`, longDescription: "Guard bands are common in production and compliance workflows." });
