    add({ category: "Python Robotics & ROS 2", name: "rclpy publisher node", description: "Create a ROS 2 publisher node with a timer callback.", insertText: `import rclpy
from rclpy.node import Node
from std_msgs.msg import Float32

class SignalPublisher(Node):
    def __init__(self) -> None:
        super().__init__("signal_publisher")
        self.publisher = self.create_publisher(Float32, "signal_level", 10)
        self.timer = self.create_timer(0.1, self.on_timer)
        self.value = 0.0

    def on_timer(self) -> None:
        msg = Float32()
        msg.data = self.value
        self.publisher.publish(msg)
        self.value += 0.1


def main() -> None:
    rclpy.init()
    node = SignalPublisher()
    try:
        rclpy.spin(node)
    finally:
        node.destroy_node()
        rclpy.shutdown()


if __name__ == "__main__":
    main()`, longDescription: "A good ROS 2 baseline when Python is used for telemetry, supervisory control, or algorithm prototyping." });
