    add({ category: "Python Robotics & ROS 2", name: "service server", description: "Expose a simple ROS 2 service in Python.", insertText: `import rclpy
from rclpy.node import Node
from example_interfaces.srv import SetBool

class BenchControl(Node):
    def __init__(self) -> None:
        super().__init__("bench_control")
        self.enabled = False
        self.service = self.create_service(SetBool, "enable_bench", self.on_enable)

    def on_enable(self, request: SetBool.Request, response: SetBool.Response) -> SetBool.Response:
        self.enabled = request.data
        response.success = True
        response.message = f"enabled={self.enabled}"
        return response`, longDescription: "Service patterns are useful when a GUI or orchestrator needs a request-response control path." });
    add({ category: "Python Robotics & ROS 2", name: "action client skeleton", description: "Send a long-running command through a ROS 2 action client.", insertText: `import rclpy
from rclpy.action import ActionClient
from rclpy.node import Node
from example_interfaces.action import Fibonacci

class SequenceClient(Node):
    def __init__(self) -> None:
        super().__init__("sequence_client")
        self.client = ActionClient(self, Fibonacci, "run_sequence")

    def send_goal(self, order: int) -> None:
        goal = Fibonacci.Goal()
        goal.order = order
        self.client.wait_for_server()
        future = self.client.send_goal_async(goal)
        future.add_done_callback(self.on_goal_response)

    def on_goal_response(self, future) -> None:
        goal_handle = future.result()
        if not goal_handle.accepted:
            self.get_logger().warning("Goal rejected")
            return
        result_future = goal_handle.get_result_async()
        result_future.add_done_callback(lambda f: self.get_logger().info(str(f.result().result.sequence)))`, longDescription: "Actions fit motor moves, calibration sequences, and other long operations with feedback." });
    add({ category: "Python Robotics & ROS 2", name: "parameters with callback", description: "Declare and validate ROS 2 parameters.", insertText: `from rcl_interfaces.msg import SetParametersResult

self.declare_parameter("sample_rate_hz", 1000.0)
self.declare_parameter("channel_name", "CH1")


def on_parameters(params):
    for param in params:
        if param.name == "sample_rate_hz" and param.value <= 0:
            return SetParametersResult(successful=False, reason="sample_rate_hz must be > 0")
    return SetParametersResult(successful=True)

self.add_on_set_parameters_callback(on_parameters)`, longDescription: "Parameter callbacks are practical for runtime tuning of DSP or acquisition nodes." });

